#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <vector>
#include <CL/cl.h>

#include "clutils.h"

#ifdef TIMING
#include <sys/time.h>

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *r) {
    r->tv_sec = t1->tv_sec - t2->tv_sec;
    r->tv_usec = t1->tv_usec - t2->tv_usec;
    if (r->tv_usec < 0) {
        r->tv_sec--;
        r->tv_usec += 1000000;
    }
}
#endif

#define min( a, b )			a > b ? b : a
#define ceilDiv( a, b )		( a + b - 1 ) / b
#define print( x )			printf( #x ": %lu\n", (unsigned long) x )
#define DEBUG				false

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53 
#define LATITUDE_POS 28	
#define OPEN 10000	

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename,std::vector<Record> &records,std::vector<LatLong> &locations);
void findLowest(std::vector<Record> &records,float *distances,int numRecords,int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d);

const char *kernel_source = 
"typedef struct latLong { float lat; float lng; } LatLong;\n"
"__kernel void euclid(__global LatLong *d_locations, __global float *d_distances, int numRecords, float lat, float lng) {\n"
"    int globalId = get_global_id(0);\n"
"    if (globalId < numRecords) {\n"
"        LatLong loc = d_locations[globalId];\n"
"        float diff_lat = lat - loc.lat;\n"
"        float diff_lng = lng - loc.lng;\n"
"        d_distances[globalId] = sqrt(diff_lat * diff_lat + diff_lng * diff_lng);\n"
"    }\n"
"}";

int main(int argc, char* argv[])
{
	int    i=0;
	float lat = 0.0f, lng = 0.0f;
	int quiet=0,timing=0,platform=0,device=0;

    std::vector<Record> records;
	std::vector<LatLong> locations;
	char filename[100];
	int resultsCount=10;

    memset(filename, 0, 100);

    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    int numRecords = loadData(filename,records,locations);
    if (numRecords == 0) {
        fprintf(stderr, "No records loaded.\n");
        return 1;
    }
    if (resultsCount > numRecords) resultsCount = numRecords;

    cl_int status;
    cl_context context;
    cl_device_id device;
    cl_command_queue command_queue;
    cl_program program;
    cl_kernel kernel;
    cl_mem d_locations_mem;
    cl_mem d_distances_mem;

    context = cl_init_context(platform, device, quiet);

    status = clGetContextInfo(context, CL_CONTEXT_DEVICES, sizeof(cl_device_id), &device, NULL);
    if (status != CL_SUCCESS) {
        fprintf(stderr, "Failed to get device from context\n");
        exit(1);
    }

    size_t maxGridX = 65535; 
    unsigned long threadsPerBlock = DEFAULT_THREADS_PER_BLOCK;

    cl_ulong totalDeviceMemory;
    status = clGetDeviceInfo(device, CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(cl_ulong), &totalDeviceMemory, NULL);
    cl_ulong freeDeviceMemory = totalDeviceMemory; 

    unsigned long usableDeviceMemory = freeDeviceMemory * 85 / 100; 
    unsigned long maxThreads = usableDeviceMemory / 12; 
    if ( numRecords > maxThreads )
    {
        fprintf( stderr, "Error: Input too large.\n" );
        exit( 1 );
    }
    unsigned long blocks = ceilDiv( numRecords, threadsPerBlock ); 
    unsigned long gridY = ceilDiv( blocks, maxGridX );
    unsigned long gridX = ceilDiv( blocks, gridY );

    if ( DEBUG )
    {
        print( totalDeviceMemory ); 
        print( freeDeviceMemory );
        print( usableDeviceMemory );
        print( maxGridX ); 
        print( threadsPerBlock );
        print( maxThreads );
        print( blocks ); 
        print( gridY );
        print( gridX );
    }

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate host memory for distances\n");
        exit(1);
    }

    d_locations_mem = cl_allocBuffer(sizeof(LatLong) * numRecords, CL_MEM_READ_WRITE);
    d_distances_mem = cl_allocBuffer(sizeof(float) * numRecords, CL_MEM_READ_WRITE);

    cl_copyBufferToDevice(d_locations_mem, &locations[0], sizeof(LatLong) * numRecords, CL_TRUE);

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, &status);
    if (status != CL_SUCCESS) {
        fprintf(stderr, "Failed to create program: %d\n", status);
        exit(1);
    }

    status = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    if (status != CL_SUCCESS) {
        fprintf(stderr, "Failed to build program: %d\n", status);
        size_t log_size;
        clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, 0, NULL, &log_size);
        char *log = (char*)malloc(log_size);
        clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, log_size, log, NULL);
        fprintf(stderr, "Build log: %s\n", log);
        free(log);
        exit(1);
    }

    kernel = clCreateKernel(program, "euclid", &status);
    if (status != CL_SUCCESS) {
        fprintf(stderr, "Failed to create kernel: %d\n", status);
        exit(1);
    }

    status = clSetKernelArg(kernel, 0, sizeof(cl_mem), &d_locations_mem);
    status |= clSetKernelArg(kernel, 1, sizeof(cl_mem), &d_distances_mem);
    status |= clSetKernelArg(kernel, 2, sizeof(int), &numRecords);
    status |= clSetKernelArg(kernel, 3, sizeof(float), &lat);
    status |= clSetKernelArg(kernel, 4, sizeof(float), &lng);

    if (status != CL_SUCCESS) {
        fprintf(stderr, "Failed to set kernel arguments: %d\n", status);
        exit(1);
    }

    size_t global_work_size = (size_t)numRecords;
    size_t local_work_size = threadsPerBlock;

    command_queue = cl_getCommandQueue();

    status = clEnqueueNDRangeKernel(command_queue, kernel, 1, NULL, &global_work_size, &local_work_size, 0, NULL, NULL);
    if (status != CL_SUCCESS) {
        fprintf(stderr, "Failed to enqueue kernel: %d\n", status);
        exit(1);
    }

    clFinish(command_queue);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    cl_copyBufferToHost(distances, d_distances_mem, sizeof(float)*numRecords, CL_TRUE);

    findLowest(records,distances,numRecords,resultsCount);

    if (!quiet)
    for(i=0;i<resultsCount;i++) {
      printf("%s --> Distance=%f\n",records[i].recString,records[i].distance);
    }
    free(distances);

    cl_freeMem(d_locations_mem);
    cl_freeMem(d_distances_mem);
    cl_freeKernel(kernel);
    cl_freeProgram(program);
    cl_cleanup();

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
    return 0;
}

int loadData(char *filename,std::vector<Record> &records,std::vector<LatLong> &locations){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist: %s\n", filename);
        exit(0);
    }

    while(!feof(flist)) {
        if(fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
            }
            break;
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db: %s\n", dbname);
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            memset(record.recString, 0, REC_LENGTH);
            if (fgets(record.recString, 49, fp) == NULL) break;
            if (feof(fp)) break;

            char substr[6];

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(std::vector<Record> &records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record *tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = &records[i];
    records[i] = records[minLoc];
    records[minLoc] = *tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; 
    strncpy(filename,argv[1],99);
    filename[99] = '\0';
    char flag;

    *r = 10; 
    *lat = 0.0f;
    *lng = 0.0f;
    *q = 0;
    *t = 0;
    *p = -1;
    *d = -1;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              i++;
              if(i<argc) *r = atoi(argv[i]);
              break;
            case 'l': 
              if (argv[i][2]=='a') {
                i++;
                if(i<argc) *lat = atof(argv[i]);
              }
              else {
                i++;
                if(i<argc) *lng = atof(argv[i]);
              }
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              if(i<argc) *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              if(i<argc) *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
      return 1;
    return 0;
}

